mapper.select:
SELECT ssg.id, ssg.id_site_group, AS text FROM site s LEFT JOIN site_sub_group ssg ON ssg.id = s.id_site_sub_group LEFT JOIN site_group sg ON sg.id = ssg.id_site_group WHERE ssg.status = 1 AND ssg.is_delete = 0 AND sg.status = 1 AND sg.is_delete = 0
AND s.id IN (
#{item.id}
)
GROUP BY ssg.id ORDER BY ssg.id ASC

SELECT AS report_name, CASE WHEN r.cadence_range = 1 THEN "Daily" WHEN r.cadence_range = 2 THEN "Month-to-Date" WHEN r.cadence_range = 3 THEN "Last Full Quarter" WHEN r.cadence_range = 4 THEN "Year-to-Date" WHEN r.cadence_range = 5 THEN "Custom" WHEN r.cadence_range = 6 THEN "Week-to-Date" WHEN r.cadence_range = 7 THEN "Last Month" WHEN r.cadence_range = 8 THEN "Last Week" ELSE "" END AS cadence_range_name, r.id, r.id_employee, r.name, r.cadence_range, r.type_report, r.data_intervals,
CONCAT_WS("#", "#subscribers", s.id) AS `subscribers`,
r.subscribers,
c.logo, c.name AS company_name, r.file_type, r.type_option, r.id_sub_group, DATE_FORMAT(r.date_from, '%Y-%m-%d 00:00:00') AS date_from, DATE_FORMAT(r.date_to, '%Y-%m-%d 23:59:59') AS date_to, r.`status`, r.schedule_enable, DATE_FORMAT(r.time_schedule, '%Y-%m-%d %H:%i') AS time_schedule, r.periodicity, r.days_week, r.offset_timezone, DATE_FORMAT(CONVERT_TZ(r.created_date, 'UTC', IFNULL(r.offset_timezone, 'UTC')), '%m/%d/%Y %H:%i %p') AS created_on, DATE_FORMAT(CONVERT_TZ(r.updated_date, 'UTC', IFNULL(r.offset_timezone, 'UTC')), '%m/%d/%Y %H:%i %p') AS last_modified, GROUP_CONCAT(s.id SEPARATOR ',') AS ids_site, JSON_ARRAYAGG(JSON_OBJECT( 'id', s.id, 'value', s.id, 'text', , 'label', , 'id_group', s.id_site_sub_group )) AS sitesListJSON FROM report r JOIN site_employee_map sem ON sem.id_employee = r.id_employee JOIN site s ON s.id = sem.id_site JOIN time_zone tz ON tz.id = s.id_time_zone LEFT JOIN site_sub_group ssg ON ssg.id = s.id_site_sub_group LEFT JOIN report_site_map rsm ON r.type_option = 2 AND rsm.id_site = s.id AND rsm.id_report = r.id LEFT JOIN company c ON c.id = s.id_company WHERE r.status = 1
AND r.id_employee = #{id_employee}
AND s.`status` = 1 AND s.is_delete = 0 AND (CONVERT_TZ(NOW(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL) AND ( CASE r.type_option WHEN 1 THEN TRUE WHEN 2 THEN rsm.id_report IS NOT NULL WHEN 3 THEN r.id_sub_group = ssg.id WHEN 4 THEN s.is_rec_report = 1 ELSE TRUE END ) GROUP BY r.id ORDER BY
r.id ${order_by}
r.name ${order_by}
r.id DESC
LIMIT ${limit} OFFSET ${offset};

SELECT count(id) as totalRow FROM ( SELECT r.id FROM report r JOIN site_employee_map sem ON sem.id_employee = r.id_employee JOIN site s ON s.id = sem.id_site JOIN time_zone tz ON tz.id = s.id_time_zone LEFT JOIN site_sub_group ssg ON ssg.id = s.id_site_sub_group LEFT JOIN report_site_map rsm ON r.type_option = 2 AND rsm.id_site = s.id AND rsm.id_report = r.id WHERE r.STATUS = 1 AND s.`status` = 1 AND s.is_delete = 0 AND (CONVERT_TZ(NOW(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL) AND ( CASE r.type_option WHEN 1 THEN TRUE WHEN 2 THEN rsm.id_report IS NOT NULL WHEN 3 THEN r.id_sub_group = ssg.id WHEN 4 THEN s.is_rec_report = 1 ELSE TRUE END )
AND r.id_employee = #{id_employee}
GROUP BY r.id ) as sub

mapper.update:
UPDATE report_log
SET
	updated_by = #{updated_by}
WHERE
	id_report = #{id}
	AND operation = 3

mapper.select:
SELECT s.id, AS name, s.id AS id_site, IF(s.rec_id IS NULL || s.rec_id = '', CONCAT_WS("-", "NWM", s.id), s.rec_id) AS rec_id, IF(s.gu_id IS NULL || s.gu_id = '', CONCAT_WS("-", "NWM", s.id), s.gu_id) AS gu_id, IFNULL(ROUND(SUM( d.energy_this_month ) / 1000, 1), 0 ) AS energy_this_month, DATE_FORMAT( #{start_date}, "%m/%d/%Y") AS start_date, DATE_FORMAT(#{end_date}, "%m/%d/%Y") AS end_date, DATE_FORMAT(#{end_date}, "%m/%Y") AS vintage_date FROM site s LEFT JOIN device d ON d.id_site = s.id WHERE s.`status` = 1 AND d.`status` = 1
AND s.id IN (
#{item.id}
)
GROUP BY s.id

SELECT t.categories_time, t.time_format, CASE WHEN #{mWh} = true THEN ROUND( CAST(t.dc_capacity AS DECIMAL) / 1000, 3 ) ELSE CAST(t.dc_capacity AS DECIMAL) END AS dc_capacity, CASE WHEN #{mWh} = true THEN ROUND( CAST(SUM(t.nvmActivePower) AS DECIMAL) / 1000, 3 ) ELSE CAST(SUM(t.nvmActivePower) AS DECIMAL) END AS power, CASE WHEN #{mWh} = true THEN ROUND( CAST(
AS DECIMAL ) / 1000, 3 ) ELSE CAST(
AS DECIMAL ) END AS energy FROM (
SELECT s.dc_capacity, s.interval_energy_threshold, s.minimum_energy_value, CONVERT_TZ( dv.time, 'UTC', t.`value` ) AS time, AS time_format, AS categories_time, m.nvmActivePower, (
) AS energy FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT (
) AS currentTimeValid, (
) AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime, LAG(MAX(dv.time), 1) OVER (ORDER BY dv.time) AS lagMaxTime, AVG(dv.nvmActivePower) AS nvmActivePower FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{item.id_site} AND s.`status` = 1 AND d.id = #{item.id} AND d.`status` = 1 AND dv.time BETWEEN CONVERT_TZ(#{start_date}, t.value, 'UTC') AND CONVERT_TZ(#{end_date}, t.value, 'UTC') AND dv.nvmActiveEnergy IS NOT NULL GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t GROUP BY t.categories_time

SELECT CAST(AVG(t.irradiance) AS DECIMAL) AS `irradiance`, t.categories_time FROM (
SELECT AS categories_time, AVG(dv.nvm_irradiance) AS irradiance FROM ${item.datatablename} dv LEFT JOIN device d ON d.id = dv.id_device LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{item.id_site} AND d.id_device_type IN(4,6) AND (CONVERT_TZ( dv.time, 'UTC', t.`value` ) BETWEEN #{start_date} AND #{end_date}) AND s.`status` = 1 AND d.`status` = 1 GROUP BY d.id, categories_time
) t GROUP BY t.categories_time

SELECT AS Timestamp, ROUND(m.nvmActivePower, 2) AS `${power_irradiance}`, ROUND(
, 2) AS `${energy_temp}`
FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT (
) AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime, AVG(dv.nvmActivePower) AS nvmActivePower FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{id_site} AND s.`status` = 1 AND d.id = #{id} AND d.`status` = 1 AND dv.time BETWEEN CONVERT_TZ(#{start_date}, t.value, 'UTC') AND CONVERT_TZ(#{end_date}, t.value, 'UTC') AND dv.nvmActiveEnergy IS NOT NULL GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{id} ORDER BY dv.time ASC
